const startTime = 8;
const finishTime = 18;

const now = new Date();
const nowHour = now.getHours();
const nowDay = now.getDay();
if (nowHour >= startTime && nowHour < finishTime && nowDay !== 0) {
      return {sheduler: true}
    }

 return {sheduler: false}

